package controller

import (
	"net/http"
	"strings"

	"github.com/hashicorp/boundary/internal/ui"
)

func init() {
	handleUi = handleUiWithAssets
}

func handleUiWithAssets(c *Controller) http.Handler {
	var nextHandler http.Handler
	if c.conf.RawConfig.PassthroughDirectory != "" {
		nextHandler = devPassthroughHandler(c.conf.RawConfig.PassthroughDirectory)

f.StringVar(&base.StringVar{
	Name:   "passthrough-directory",
	Target: &c.flagPassthroughDirectory,
	EnvVar: "BOUNDARY_DEV_PASSTHROUGH_DIRECTORY",
	Usage:  "Enables a passthrough directory in the webserver at /",
})

f.StringVar(&base.StringVar{
	Name:   "recovery-key",
	Target: &c.flagRecoveryKey,
	EnvVar: "BOUNDARY_DEV_RECOVERY_KEY",
	Usage:  "Specifies the base64'd 256-bit AES key to use for recovery operations",
})

f.StringVar(&base.StringVar{
	Name:   "database-url",
	Target: &c.flagDatabaseUrl,
	Usage:  `If set, specifies the URL used to connect to the database for initialization (otherwise a Docker container will be started). This can refer to a file on disk (file://) from which a URL will be read; an env var (env://) from which the URL will be read; or a direct database URL.`,
})

package controller

import (
	"context"
	"net/http"
	"path/filepath"

	"github.com/hashicorp/boundary/internal/observability/event"
)

func devPassthroughHandler(passthroughDir string) http.Handler {
	const op = "controller.devPassthroughHandler"
	ctx := context.TODO()
	// Panic may not be ideal but this is never a production call and it'll
	// panic on startup. We could also just change the function to return
	// an error.
	abs, err := filepath.Abs(passthroughDir)
	if err != nil {
		panic(err)
	}
